// 获取穴位所属的部位分类
export function getBodyPartCategories(pointName) {
  return bodyPartCategories.filter(cat => cat.points.includes(pointName));
}

// 获取穴位所属的症状分类
export function getSymptomCategories(pointName) {
  return symptomCategories.filter(cat => cat.points.includes(pointName));
}
